import type {CursorPage, JournalItem} from '../api/mobileApi';

export const extractPlainText = (rawContent: string | null | undefined): string => {
  if (!rawContent) return '';
  try {
    const parsed = JSON.parse(rawContent) as {
      root?: {children?: Array<{children?: Array<{text?: string}>}>};
    };
    const parts: string[] = [];
    parsed.root?.children?.forEach(node => {
      node.children?.forEach(child => {
        if (child.text) parts.push(child.text);
      });
    });
    return parts.join(' ').replace(/\s+/g, ' ').trim();
  } catch {
    return rawContent.replace(/\s+/g, ' ').trim();
  }
};

export const extractBannerImage = (
  rawContent: string | null | undefined,
  images?: string | string[] | null,
): string | null => {
  if (images) {
    if (typeof images === 'string') {
      try {
        const parsed = JSON.parse(images);
        if (Array.isArray(parsed) && parsed.length > 0) return parsed[0];
      } catch {
        if (images.startsWith('http')) return images;
      }
    }
    if (Array.isArray(images) && images.length > 0) return images[0];
  }
  if (!rawContent) return null;
  try {
    const parsed = JSON.parse(rawContent);
    const findImage = (node: any): string | null => {
      if (node.type === 'image' && node.src) return node.src;
      if (node.children) {
        for (const child of node.children) {
          const found = findImage(child);
          if (found) return found;
        }
      }
      return null;
    };
    return findImage(parsed.root ?? parsed);
  } catch {
    return null;
  }
};

export const normalizeCount = (value: unknown): number => {
  const parsed = Number(value);
  return Number.isFinite(parsed) && parsed >= 0 ? parsed : 0;
};

export const resolveCount = (
  aggregate: Array<{count?: number}> | undefined,
  fallback?: number,
): number => {
  if (Array.isArray(aggregate) && aggregate.length > 0)
    return normalizeCount(aggregate[0]?.count);
  return normalizeCount(fallback);
};

export const calculateReadingTime = (text: string): string => {
  const wordPerMin = 150;
  const words = text.trim().split(/\s+/).length;
  const readingTime = Math.ceil(words / wordPerMin);
  if (readingTime > 1) {
    return `${readingTime} mins read`;
  }
  return `${readingTime} min read`;
};

export const getNextCursor = (
  page: CursorPage<JournalItem>,
  pageSize: number,
): string | undefined => {
  if (page.nextCursor) return page.nextCursor;
  if (page.hasMore && page.data.length > 0)
    return page.data[page.data.length - 1]?.created_at ?? undefined;
  if (page.data.length >= pageSize)
    return page.data[page.data.length - 1]?.created_at ?? undefined;
  return undefined;
};

import React, {useEffect, useMemo, useState} from 'react';
import {
  FlatList,
  Pressable,
  StyleSheet,
  Text,
  View,
} from 'react-native';
import {useInfiniteQuery, useMutation, useQuery} from '@tanstack/react-query';
import {BottomTabScreenProps} from '@react-navigation/bottom-tabs';
import {CompositeScreenProps} from '@react-navigation/native';
import {NativeStackScreenProps} from '@react-navigation/native-stack';
import {SafeAreaView} from 'react-native-safe-area-context';
import {PostCard} from '../../components/PostCard/PostCard';
import {PostCardSkeleton} from '../../components/SkeletonLoader';
import {CommentModal} from '../../components/Comments';
import {RepostModal} from '../../components/RepostModal';
import {SearchInput} from '../../components/SearchInput';
import {SearchResultsView} from '../../components/SearchResultsView';
import {FeedTabBar, type FeedTab} from '../../components/FeedTabBar';
import {DailyPromptCard} from '../../components/DailyPromptCard';
import {EmptyState} from '../../components/EmptyState';
import {WeeklyRecapModal} from '../../components/WeeklyRecapModal';
import {PenIcon} from '../../components/icons';
import {analyticsApi, type WeeklyRecapData} from '../../lib/api/analyticsApi';
import {useAuth} from '../../features/auth/AuthProvider';
import {useTheme} from '../../theme/ThemeProvider';
import {fonts, typeScale} from '../../theme/typography';
import {spacing, radii, shadows} from '../../theme/spacing';
import {
  mobileApi,
  type CursorPage,
  type JournalItem,
} from '../../lib/api/mobileApi';
import {socialApi} from '../../lib/api/socialApi';
import {queryClient} from '../../lib/queryClient';
import {useBookmarkMutation} from '../../hooks/useSocialMutations';
import {useSearch} from '../../hooks/useSearch';
import {
  extractPlainText,
  extractBannerImage,
  resolveCount,
  getNextCursor,
} from '../../lib/utils/journalHelpers';
import type {MainTabParamList, RootStackParamList} from '../../navigation/types';

type Props = CompositeScreenProps<
  BottomTabScreenProps<MainTabParamList, 'Home'>,
  NativeStackScreenProps<RootStackParamList>
>;

const PAGE_SIZE = 10;

export function HomeFeedScreen({navigation}: Props) {
  const {user, session} = useAuth();
  const {colors} = useTheme();
  const token = session?.access_token ?? '';
  const [refreshing, setRefreshing] = useState(false);
  const [feedTab, setFeedTab] = useState<FeedTab>('all');
  const [forYouOffset, setForYouOffset] = useState(0);
  const [commentModal, setCommentModal] = useState<{postId: string; receiverId?: string; commentCount: number} | null>(null);
  const [repostModal, setRepostModal] = useState<{journalId: string; title?: string; authorName?: string; authorAvatar?: string} | null>(null);
  const [showRecap, setShowRecap] = useState(false);
  const [recapData, setRecapData] = useState<WeeklyRecapData | null>(null);
  const {query, setQuery, activeTab, setActiveTab, isSearching, normalizedQuery, users, journals} = useSearch();

  const recapQuery = useQuery({
    queryKey: ['weekly-recap'],
    enabled: Boolean(token),
    queryFn: () => analyticsApi.getWeeklyRecap(token),
    staleTime: 60 * 60 * 1000,
  });

  useEffect(() => {
    if (recapQuery.data?.recap?.available && !showRecap && !recapData) {
      setRecapData(recapQuery.data.recap);
      setShowRecap(true);
    }
  }, [recapQuery.data]);

  const feedQuery = useInfiniteQuery({
    queryKey: ['feed', user?.id],
    enabled: feedTab === 'all',
    queryFn: ({pageParam}) =>
      mobileApi.getJournals(pageParam ?? null, PAGE_SIZE, user?.id),
    initialPageParam: null as string | null,
    getNextPageParam: lastPage => getNextCursor(lastPage, PAGE_SIZE),
  });

  const followingQuery = useInfiniteQuery({
    queryKey: ['feed-following', user?.id],
    enabled: feedTab === 'following' && Boolean(token),
    queryFn: ({pageParam}) =>
      mobileApi.getFollowingFeed(token, pageParam ?? null, PAGE_SIZE),
    initialPageParam: null as string | null,
    getNextPageParam: lastPage => getNextCursor(lastPage, PAGE_SIZE),
  });

  const forYouQuery = useInfiniteQuery({
    queryKey: ['feed-foryou', user?.id],
    enabled: feedTab === 'foryou' && Boolean(token),
    queryFn: ({pageParam}) =>
      mobileApi.getForYouFeed(token, (pageParam as number) ?? 0, PAGE_SIZE),
    initialPageParam: 0 as number,
    getNextPageParam: (lastPage, allPages) =>
      (lastPage.data?.length ?? 0) >= PAGE_SIZE ? allPages.length * PAGE_SIZE : undefined,
  });

  const activeQuery = feedTab === 'following' ? followingQuery : feedTab === 'foryou' ? forYouQuery : feedQuery;

  const reactionMutation = useMutation({
    mutationFn: async ({
      journalId,
      receiverId,
      reactionType,
    }: {
      journalId: string;
      receiverId: string;
      reactionType: string;
    }) => {
      if (!token) throw new Error('Please log in to react.');
      return socialApi.toggleReaction(token, {journalId, receiverId, reactionType});
    },
    onMutate: async ({journalId, reactionType}) => {
      await queryClient.cancelQueries({queryKey: ['feed']});
      const prev = queryClient.getQueryData<{pages: CursorPage<JournalItem>[]}>(
        ['feed', user?.id],
      );
      if (prev) {
        queryClient.setQueryData<{pages: CursorPage<JournalItem>[]}>(
          ['feed', user?.id],
          old => {
            if (!old) return old;
            return {
              ...old,
              pages: old.pages.map(page => ({
                ...page,
                data: page.data.map(item => {
                  if (item.id !== journalId) return item;
                  const removing = item.user_reaction === reactionType;
                  const currentCount =
                    (item.reaction_count?.[0]?.count ??
                      item.like_count?.[0]?.count ??
                      item.likes_count ??
                      0) as number;
                  const delta = removing ? -1 : item.user_reaction ? 0 : 1;
                  return {
                    ...item,
                    user_reaction: removing ? null : reactionType,
                    has_liked: removing ? false : true,
                    like_count: [{count: Math.max(0, currentCount + delta)}],
                  };
                }),
              })),
            };
          },
        );
      }
      return {prev};
    },
    onError: (_err, _vars, context) => {
      if (context?.prev) {
        queryClient.setQueryData(['feed', user?.id], context.prev);
      }
    },
    onSettled: () => {
      queryClient.invalidateQueries({queryKey: ['feed']});
    },
  });

  const bookmarkMutation = useBookmarkMutation(token, ['feed', user?.id]);

  const handleReact = (journalId: string, receiverId: string, reactionType: string) => {
    if (!token) return;
    reactionMutation.mutate({journalId, receiverId, reactionType});
  };

  const handleComment = (journalId: string, receiverId?: string, commentCount?: number) => {
    setCommentModal({postId: journalId, receiverId, commentCount: commentCount ?? 0});
  };

  const handleBookmark = (journalId: string) => {
    bookmarkMutation.mutate(journalId);
  };

  const handleRepost = (journalId: string, title?: string, authorName?: string, authorAvatar?: string) => {
    setRepostModal({journalId, title, authorName, authorAvatar});
  };

  const handleAuthorPress = (item: JournalItem) => {
    const authorId = item.users?.id ?? item.user_id;
    if (!authorId) return;
    if (authorId === user?.id) {
      navigation.navigate('Main' as any, {screen: 'Profile'});
    } else {
      navigation.navigate('VisitProfile', {
        userId: authorId,
        username: item.users?.username ?? undefined,
      });
    }
  };

  const posts = useMemo(
    () => activeQuery.data?.pages.flatMap(page => page.data ?? []) ?? [],
    [activeQuery.data?.pages],
  );

  const onRefresh = async () => {
    setRefreshing(true);
    try {
      await activeQuery.refetch();
    } finally {
      setRefreshing(false);
    }
  };

  return (
    <SafeAreaView
      style={[styles.safe, {backgroundColor: colors.bgPrimary}]}
      edges={['top']}>
      {/* Branded header */}
      <View
        style={[
          styles.header,
          {borderBottomColor: colors.borderCard},
        ]}>
        <Text style={[styles.brandText, {color: colors.textHeading}]}>
          iskrib
        </Text>
        <SearchInput
          value={query}
          onChangeText={setQuery}
          placeholder="Search users or posts..."
          autoCapitalize="none"
          returnKeyType="search"
        />
      </View>

      {isSearching ? (
        <SearchResultsView
          activeTab={activeTab}
          onTabChange={setActiveTab}
          users={users}
          journals={journals}
          normalizedQuery={normalizedQuery}
          onUserPress={(id, username) =>
            navigation.navigate('VisitProfile', {userId: id, username})
          }
          onPostPress={id =>
            navigation.navigate('PostDetail', {journalId: id})
          }
          onAuthorPress={handleAuthorPress}
          onReact={handleReact}
          onComment={handleComment}
          onBookmark={handleBookmark}
          onRepost={handleRepost}
          onEmbeddedPress={id =>
            navigation.navigate('PostDetail', {journalId: id})
          }
        />
      ) : (
        <>
          {/* Feed tab bar */}
          <FeedTabBar activeTab={feedTab} onTabChange={setFeedTab} />

          {/* Feed */}
          <FlatList
            data={posts}
            onRefresh={onRefresh}
            refreshing={refreshing}
            onEndReachedThreshold={0.25}
            onEndReached={() => {
              if (activeQuery.hasNextPage && !activeQuery.isFetchingNextPage) {
                activeQuery.fetchNextPage();
              }
            }}
            contentContainerStyle={styles.listContent}
            showsVerticalScrollIndicator={false}
            ListHeaderComponent={
              feedTab === 'all' ? <DailyPromptCard onWrite={(promptId, promptText) => navigation.navigate('JournalEditor', {mode: 'create'})} /> : null
            }
            ListEmptyComponent={
              activeQuery.isLoading ? (
                <View style={styles.skeletonList}>
                  <PostCardSkeleton />
                  <PostCardSkeleton />
                  <PostCardSkeleton />
                </View>
              ) : (
                <EmptyState
                  title={feedTab === 'following' ? 'No posts from people you follow' : feedTab === 'foryou' ? 'No recommendations yet' : 'No posts yet'}
                  subtitle={feedTab === 'following' ? 'Follow writers to see their posts here.' : 'Pull to refresh or create your first journal post.'}
                />
              )
            }
            ListFooterComponent={
              activeQuery.isFetchingNextPage ? (
                <View style={styles.loadingMore}>
                  <PostCardSkeleton />
                </View>
              ) : null
            }
            keyExtractor={item => item.id}
            renderItem={({item}) => {
              const preview = extractPlainText(item.content).slice(0, 180);
              const likeCount = resolveCount(
                item.like_count,
                item.likes_count,
              );
              const commentCount = resolveCount(
                item.comment_count,
                item.comments_count,
              );
              const bookmarkCount = resolveCount(item.bookmark_count);
              const bannerImage = extractBannerImage(
                item.content,
                (item as any).images,
              );

              const receiverId = item.user_id ?? item.users?.id ?? '';

              const isRepost = !!item.is_repost;
              const repostSource = isRepost ? item.repost_source : null;
              const repostSourcePreview = repostSource?.preview_text || '';

              return (
                <PostCard
                  title={item.title || 'Untitled Post'}
                  bodyPreview={preview || 'No preview text available.'}
                  authorName={item.users?.name || 'Unknown author'}
                  authorAvatar={item.users?.image_url}
                  authorBadge={item.users?.badge as 'legend' | 'og' | undefined}
                  bannerImage={bannerImage}
                  postType={item.post_type}
                  likeCount={likeCount}
                  commentCount={commentCount}
                  bookmarkCount={bookmarkCount}
                  userReaction={item.user_reaction}
                  isBookmarked={!!item.has_bookmarked}
                  onReact={type => handleReact(item.id, receiverId, type)}
                  onComment={() => handleComment(item.id, receiverId, commentCount)}
                  onBookmark={() => handleBookmark(item.id)}
                  onRepost={() => handleRepost(item.id, item.title ?? undefined, item.users?.name ?? undefined, item.users?.image_url ?? undefined)}
                  onPress={() =>
                    navigation.navigate('PostDetail', {journalId: item.id})
                  }
                  onAuthorPress={() => handleAuthorPress(item)}
                  isRepost={isRepost}
                  repostCaption={item.repost_caption}
                  repostSourceTitle={repostSource?.title}
                  repostSourcePreview={repostSourcePreview}
                  repostSourceAuthorName={repostSource?.users?.name}
                  repostSourceAuthorAvatar={repostSource?.users?.image_url}
                  onEmbeddedPress={repostSource ? () => navigation.navigate('PostDetail', {journalId: repostSource.id}) : undefined}
                />
              );
            }}
            ItemSeparatorComponent={() => <View style={styles.separator} />}
          />
        </>
      )}

      {commentModal && (
        <CommentModal
          visible
          postId={commentModal.postId}
          receiverId={commentModal.receiverId}
          commentCount={commentModal.commentCount}
          onClose={() => setCommentModal(null)}
        />
      )}

      {repostModal && (
        <RepostModal
          visible
          sourceJournalId={repostModal.journalId}
          title={repostModal.title}
          authorName={repostModal.authorName}
          authorAvatar={repostModal.authorAvatar}
          onClose={() => setRepostModal(null)}
        />
      )}

      {recapData && (
        <WeeklyRecapModal
          visible={showRecap}
          recap={recapData}
          onDismiss={() => setShowRecap(false)}
        />
      )}

      {/* FAB Write Button */}
      <Pressable
        onPress={() => navigation.navigate('JournalEditor', {mode: 'create'})}
        style={({pressed}) => [
          styles.fab,
          {backgroundColor: colors.accentAmber},
          shadows(colors).elevated,
          pressed && styles.fabPressed,
        ]}>
        <PenIcon size={22} color="#1A1612" />
      </Pressable>
    </SafeAreaView>
  );
}

