              commentCount={resolveCount(item.comment_count, item.comments_count)}
              bookmarkCount={resolveCount(item.bookmark_count)}
              bannerImage={bannerImage}
              onPress={() => navigation.navigate('PostDetail', {journalId: item.id})}
              onAuthorPress={() => {
                const authorId = item.users?.id ?? item.user_id;
                if (authorId && authorId !== user?.id) {
                  navigation.navigate('VisitProfile', {userId: authorId});
                }
              }}
              onReact={() => {}}
              onComment={() => {}}
              onBookmark={() => {}}
              onRepost={() => {}}
            />
          );
        }}
        ItemSeparatorComponent={() => <View style={styles.separator} />}
      />
    </SafeAreaView>
  );
}

