 14→} from '../../lib/utils/profileBackground';
 15→
 16→interface ProfileHeroProps {
 17→  profile: {
 18→    id: string;
 19→    name?: string;
 20→    username?: string;
 21→    bio?: string;
 22→    image_url?: string;
 23→    badge_type?: string;
 24→    profile_layout?: any;
 25→    followers_count?: number;
 26→    following_count?: number;
 27→    posts_count?: number;
 28→    background?: Record<string, string> | null;
 29→    profile_font_color?: string | null;
 30→    dominant_colors?: string | null;
 31→    secondary_colors?: string | null;
 32→  } | null;
 33→  streak?: number;
 34→  longestStreak?: number;
 35→  email?: string;
 36→  onEditProfile?: () => void;
 37→  onSettingsPress?: () => void;
 38→  onFollowersPress: () => void;
 39→  onFollowingPress: () => void;
 40→  actionButton?: React.ReactNode;
 41→}
 42→
 43→export function ProfileHeroSection({
 44→  profile,
 45→  streak,
 46→  longestStreak,
 47→  email,
 48→  onEditProfile,
 49→  onSettingsPress,
 50→  onFollowersPress,
 51→  onFollowingPress,
 52→  actionButton,
 53→}: ProfileHeroProps) {
 54→  const {colors} = useTheme();
 55→  const bgColor = profile?.profile_layout?.backgroundColor ?? colors.accentAmber;
 56→
 57→  const parsedBg = useMemo(
 58→    () => parseProfileBackground(profile?.background),
 59→    [profile?.background],
 60→  );
 61→
 62→  const fontColor = profile?.profile_font_color || null;
 63→  const nameColor = fontColor || colors.textHeading;
 64→  const mutedColor = fontColor ? `${fontColor}99` : colors.textMuted;
 65→  const secondaryColor = fontColor ? `${fontColor}CC` : colors.textSecondary;
 66→  const iconColor = fontColor ? `${fontColor}CC` : 'rgba(255,255,255,0.8)';
 67→  const shareIconColor = fontColor ? `${fontColor}CC` : colors.textSecondary;
 68→
 69→  const onShareProfile = async () => {
 70→    const username = profile?.username || profile?.name || 'user';
 71→    try {
 72→      await Share.share({
 73→        message: `Check out @${username} on iskrib!\nhttps://iskrib.com/${username}`,
 74→      });
 75→    } catch {
 76→      // User cancelled
 77→    }
 78→  };
 79→
 80→  return (
 81→    <View>
 82→      {/* Background header */}
 83→      {parsedBg.type === 'gradient' ? (
 84→        <LinearGradient
 85→          colors={parsedBg.colors}
 86→          locations={parsedBg.locations}
 87→          {...cssAngleToGradientPoints(parsedBg.angle)}
 88→          style={styles.headerBg}>
 89→          {onSettingsPress && (
 90→            <Pressable
 91→              style={styles.settingsBtn}
 92→              onPress={onSettingsPress}
 93→              hitSlop={12}>
 94→              <SettingsIcon size={22} color={iconColor} />
 95→            </Pressable>
 96→          )}
 97→        </LinearGradient>
 98→      ) : parsedBg.type === 'image' ? (
 99→        <ImageBackground
100→          source={{uri: parsedBg.uri}}
101→          style={styles.headerBg}
102→          imageStyle={styles.headerBgImage}
103→          resizeMode="cover">
104→          {onSettingsPress && (
105→            <Pressable
106→              style={styles.settingsBtn}
107→              onPress={onSettingsPress}
108→              hitSlop={12}>
109→              <SettingsIcon size={22} color={iconColor} />
110→            </Pressable>
111→          )}
112→        </ImageBackground>
113→      ) : (
114→        <View style={[styles.headerBg, {backgroundColor: bgColor}]}>
115→          {onSettingsPress && (
116→            <Pressable
117→              style={styles.settingsBtn}
118→              onPress={onSettingsPress}
119→              hitSlop={12}>
120→              <SettingsIcon size={22} color={iconColor} />
121→            </Pressable>
122→          )}
123→        </View>
124→      )}
125→
126→      <View style={styles.profileContent}>
127→        {/* Avatar + Stats row */}
128→        <View style={styles.avatarStatsRow}>
129→          <View style={styles.avatarWrap}>
130→            <Avatar
131→              uri={profile?.image_url}
132→              name={profile?.name}
133→              size={80}
134→              badge={profile?.badge_type as any}
135→            />
136→          </View>
137→
138→          <View style={styles.statsRow}>
139→            <View style={styles.statItem}>
140→              <Text style={[styles.statNumber, {color: nameColor}]}>
141→                {profile?.posts_count ?? 0}
142→              </Text>
143→              <Text style={[styles.statLabel, {color: mutedColor}]}>
144→                Posts
145→              </Text>
146→            </View>
147→            <Pressable style={styles.statItem} onPress={onFollowersPress}>
148→              <Text style={[styles.statNumber, {color: nameColor}]}>
149→                {profile?.followers_count ?? 0}
150→              </Text>
151→              <Text style={[styles.statLabel, {color: mutedColor}]}>
152→                Followers
153→              </Text>
154→            </Pressable>
155→            <Pressable style={styles.statItem} onPress={onFollowingPress}>
156→              <Text style={[styles.statNumber, {color: nameColor}]}>
157→                {profile?.following_count ?? 0}
158→              </Text>
159→              <Text style={[styles.statLabel, {color: mutedColor}]}>
160→                Following
161→              </Text>
162→            </Pressable>
163→          </View>
164→        </View>
165→
166→        {/* Name row */}
167→        <View style={styles.nameSection}>
168→          <Text style={[styles.name, {color: nameColor}]}>
169→            {profile?.name || email || 'User'}
170→          </Text>
171→          {profile?.username ? (
172→            <Text style={[styles.username, {color: mutedColor}]}>
173→              @{profile.username}
174→            </Text>
175→          ) : null}
176→
177→          <View style={styles.badgeRow}>
178→            {profile?.badge_type ? (
179→              <View
180→                style={[
181→                  styles.badgePill,
182→                  {
183→                    backgroundColor:
184→                      profile.badge_type === 'legend'
185→                        ? 'rgba(255,215,0,0.15)'
186→                        : 'rgba(155,89,255,0.15)',
187→                    borderColor:
188→                      profile.badge_type === 'legend'
189→                        ? colors.badgeLegendBorder
190→                        : colors.badgeOGBorder,
191→                  },
192→                ]}>
193→                <Text
194→                  style={[
195→                    styles.badgeText,
196→                    {
197→                      color:
198→                        profile.badge_type === 'legend'
199→                          ? colors.badgeLegendBorder
200→                          : colors.badgeOGBorder,
201→                    },
202→                  ]}>
203→                  {profile.badge_type.toUpperCase()}
204→                </Text>
205→              </View>
206→            ) : null}
207→
208→            {streak != null && streak > 0 ? (
209→              <View style={[styles.streakBadge, {backgroundColor: 'rgba(245,158,11,0.12)'}]}>
210→                <FireIcon size={14} color="#F59E0B" />
211→                <Text style={styles.streakText}>
212→                  {streak}{longestStreak != null && longestStreak > streak ? ` / ${longestStreak}` : ''}
213→                </Text>
214→              </View>
215→            ) : null}
216→          </View>
217→        </View>
218→
219→        {/* Bio */}
220→        {profile?.bio ? (
221→          <Text style={[styles.bio, {color: secondaryColor}]}>
222→            {profile.bio}
223→          </Text>
224→        ) : null}
225→
226→        {/* Action row */}
227→        <View style={styles.actionRow}>
228→          <View style={styles.editBtn}>
229→            {onEditProfile ? (
230→              <PrimaryButton
231→                label="Edit Profile"
232→                onPress={onEditProfile}
233→                kind="secondary"
234→              />
235→            ) : actionButton ? (
236→              actionButton
237→            ) : null}
238→          </View>
239→          <Pressable
240→            style={[styles.shareBtn, {borderColor: colors.borderLight}]}
241→            onPress={onShareProfile}
242→            hitSlop={8}>
243→            <ShareIcon size={18} color={shareIconColor} />
244→          </Pressable>
245→        </View>
