 12→  getPreviewText,
 13→  extractBannerImage,
 14→  resolveCount,
 15→  getNextCursor,
 16→} from '../../lib/utils/journalHelpers';
 17→import {mobileApi, type CursorPage, type JournalItem} from '../../lib/api/mobileApi';
 18→import {socialApi} from '../../lib/api/socialApi';
 19→import {queryClient} from '../../lib/queryClient';
 20→import {useAuth} from '../../features/auth/AuthProvider';
 21→import {useBookmarkMutation} from '../../hooks/useSocialMutations';
 22→import {spacing} from '../../theme/spacing';
