 3→export const getPreviewText = (item: {preview_text?: string | null; content?: string | null}): string => {
 4→  if (item.preview_text) return item.preview_text;
 5→  return extractPlainText(item.content);
 6→};
 7→
 8→export const extractPlainText = (rawContent: string | null | undefined): string => {
 9→  if (!rawContent) return '';
10→  try {
11→    const parsed = JSON.parse(rawContent) as {
12→      root?: {children?: Array<{children?: Array<{text?: string}>}>};
13→    };
14→    const parts: string[] = [];
15→    parsed.root?.children?.forEach(node => {
16→      node.children?.forEach(child => {
17→        if (child.text) parts.push(child.text);
18→      });
19→    });
20→    return parts.join(' ').replace(/\s+/g, ' ').trim();
21→  } catch {
22→    return rawContent.replace(/\s+/g, ' ').trim();
23→  }
24→};
