26→export const extractBannerImage = (
27→  rawContent: string | null | undefined,
28→  images?: string | string[] | null,
29→): string | null => {
30→  if (images) {
31→    if (typeof images === 'string') {
32→      try {
33→        const parsed = JSON.parse(images);
34→        if (Array.isArray(parsed) && parsed.length > 0) return parsed[0];
35→      } catch {
36→        if (images.startsWith('http')) return images;
37→      }
38→    }
39→    if (Array.isArray(images) && images.length > 0) return images[0];
40→  }
41→  if (!rawContent) return null;
42→  try {
43→    const parsed = JSON.parse(rawContent);
44→    const findImage = (node: any): string | null => {
45→      if (node.type === 'image' && node.src) return node.src;
46→      if (node.children) {
47→        for (const child of node.children) {
48→          const found = findImage(child);
49→          if (found) return found;
50→        }
51→      }
52→      return null;
53→    };
54→    return findImage(parsed.root ?? parsed);
55→  } catch {
56→    return null;
57→  }
58→};
