60→export const normalizeCount = (value: unknown): number => {
61→  const parsed = Number(value);
62→  return Number.isFinite(parsed) && parsed >= 0 ? parsed : 0;
63→};
64→
65→export const resolveCount = (
66→  aggregate: Array<{count?: number}> | undefined,
67→  fallback?: number,
68→): number => {
69→  if (Array.isArray(aggregate) && aggregate.length > 0)
70→    return normalizeCount(aggregate[0]?.count);
71→  return normalizeCount(fallback);
72→};
