74→export const calculateReadingTime = (text: string): string => {
75→  const wordPerMin = 150;
76→  const words = text.trim().split(/\s+/).length;
77→  const readingTime = Math.ceil(words / wordPerMin);
78→  if (readingTime > 1) {
79→    return `${readingTime} mins read`;
80→  }
81→  return `${readingTime} min read`;
82→};
