84→export const getNextCursor = (
85→  page: CursorPage<JournalItem>,
86→  pageSize: number,
87→): string | undefined => {
88→  if (page.nextCursor) return page.nextCursor;
89→  if (page.hasMore && page.data.length > 0)
90→    return page.data[page.data.length - 1]?.created_at ?? undefined;
91→  if (page.data.length >= pageSize)
92→    return page.data[page.data.length - 1]?.created_at ?? undefined;
93→  return undefined;
94→};
